import{_ as t,o,c as a,ag as r}from"./chunks/framework.1N8rnUr9.js";const p=JSON.parse('{"title":"Quick Start Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":null}'),i={name:"guide/getting-started.md"};function n(l,e,s,u,d,c){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="quick-start-guide" tabindex="-1">Quick Start Guide <a class="header-anchor" href="#quick-start-guide" aria-label="Permalink to &quot;Quick Start Guide&quot;">​</a></h1><p>This guide will walk you through setting up TubeBay and mapping your first YouTube video to a WooCommerce product in less than two minutes.</p><h2 id="step-1-connect-your-youtube-account" tabindex="-1">Step 1: Connect your YouTube Account <a class="header-anchor" href="#step-1-connect-your-youtube-account" aria-label="Permalink to &quot;Step 1: Connect your YouTube Account&quot;">​</a></h2><p>The first time you visit the TubeBay menu, you&#39;ll see the <strong>Welcome Screen</strong>.</p><ol><li>Click <strong>Start Setup Wizard</strong>.</li><li>Choose <strong>Google OAuth</strong> (Recommended).</li><li>Follow the prompts to authorize your account.</li><li>Paste your <strong>Refresh Token</strong> and click <strong>Connect</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">Already have an API Key?</p><p>You can also connect manually via the <strong>Manual API</strong> tab if you prefer to use your own Google Cloud project credentials.</p></div><h2 id="step-2-sync-your-video-library" tabindex="-1">Step 2: Sync Your Video Library <a class="header-anchor" href="#step-2-sync-your-video-library" aria-label="Permalink to &quot;Step 2: Sync Your Video Library&quot;">​</a></h2><p>Once connected, TubeBay needs to pull your videos from YouTube.</p><ol><li>Click <strong>Sync Library</strong> in the wizard (or go to the <strong>Library</strong> tab).</li><li>TubeBay will fetch your latest uploads.</li><li>You should see a list of your videos with thumbnails and titles appearing in the dashboard.</li></ol><h2 id="step-3-map-a-video-to-a-product" tabindex="-1">Step 3: Map a Video to a Product <a class="header-anchor" href="#step-3-map-a-video-to-a-product" aria-label="Permalink to &quot;Step 3: Map a Video to a Product&quot;">​</a></h2><p>Now that your videos are synced, you can link them to your WooCommerce products.</p><ol><li>In the <strong>Library</strong> tab, find a video you want to use.</li><li>Click the <strong>Map to Product</strong> button next to that video.</li><li>Search for your product by name in the popup search box.</li><li>Select the desired product and click <strong>Confirm</strong>.</li></ol><h2 id="step-4-configure-the-video-player" tabindex="-1">Step 4: Configure the Video Player <a class="header-anchor" href="#step-4-configure-the-video-player" aria-label="Permalink to &quot;Step 4: Configure the Video Player&quot;">​</a></h2><p>Before viewing the video on the frontend, check how it should behave.</p><ol><li>Navigate to <strong>TubeBay &gt; Settings</strong>.</li><li>Go to the <strong>Video Player</strong> tab.</li><li>Set your preferred <strong>Placement</strong> (e.g., &quot;Below Product Gallery&quot;).</li><li>Toggle options like <strong>Muted Autoplay</strong> or <strong>Hide Controls</strong>.</li><li>Click <strong>Save Settings</strong>.</li></ol><h2 id="step-5-view-on-frontend" tabindex="-1">Step 5: View on Frontend <a class="header-anchor" href="#step-5-view-on-frontend" aria-label="Permalink to &quot;Step 5: View on Frontend&quot;">​</a></h2><p>Visit the product page you just mapped a video to. You should see the TubeBay player embedded in your chosen location!</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next?&quot;">​</a></h2><ul><li>Learn more about <a href="/tubebay/guide/connection.html">Connection Methods</a>.</li><li>Optimize your <a href="/tubebay/guide/sync-library.html">Sync Schedule</a>.</li><li>Explore <a href="/tubebay/features/shortcodes.html">Shortcodes</a> for custom video placement.</li></ul>',19)])])}const g=t(i,[["render",n]]);export{p as __pageData,g as default};
